class Util{static checkDuplicate(e,t,a){let s=[],i;if(a){Wb.set("_sid",a);s.push("sid<>{?_sid?}")}Wb.set("_name",e);s.push("name={?_name?}");if(t){Wb.set("_groupName",t);s.push("group_name={?_groupName?}")}else{s.push("(group_name is null or group_name='')")}i=Wb.getRow("select 1 from wb_dict where "+s.join(" and "));if(i)Wb.raise(Str.alreadyExists.format(t?t+"."+e:e))}static clearBuffer(e){let t=DictCls.buffer,a,s;e.forEach((e=>{s=e.name;a=e.group_name;if(a)s=a+"."+s;t.remove(s);e.alias?.splitTrim().forEach((e=>{if(e){s=e;if(a)s=a+"."+s;t.remove(s)}}))}))}static updateBuffer(e){let t=Wb.sqlRS("select * from wb_dict where sid={?"+(e?"$":"")+"sid?}").resultSet;t.next();DictCls.updateData(t,null)}}export default Util;